code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Checkbox, icon } from 'decantr/components';

code.example:
function ChecklistCard({ title, items }) {
  const { div, h3, span } = tags;

  return Card({},
    Card.Header({},
      div({ class: css('_flex _aic _jcsb') },
        h3({ class: css('_heading5') }, icon('list'), ` ${title}`),
        span({ class: css('_textsm _fgmuted') }, `${items.length} items`)
      )
    ),
    Card.Body({ class: css('_flex _col _gap2') },
      ...items.map(item =>
        Checkbox({ label: typeof item === 'string' ? item : `${item.quantity} ${item.unit} ${item.name}${item.preparation ? ' — ' + item.preparation : ''}` })
      )
    )
  );
}

